1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface ClaimStep {
23	  op: "claim";
24	  policy: number;
25	  incident: {
26	    cause?: string;
27	    damages: Damage[];
28	  };
29	}
30	
31	export type Step = QuoteStep | ClaimStep;
32	
33	export interface Scenario {
34	  customer: Customer;
35	  steps: Step[];
36	}
37	
38	export interface QuoteResult {
39	  premium: number;
40	}
41	
42	export interface ClaimResult {
43	  payout: number;
44	  remainingCap: number;
45	}
46	
47	export type StepResult = QuoteResult | ClaimResult;
48	
49	export interface ScenarioResult {
50	  results: StepResult[];
51	}
