53	const PROCESSING_FEE = 5;
54	
55	const ITEM_BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	  moonstone: 25,
62	};
63	
64	const basePremiumFor = (item: Item): number => ITEM_BASE_PREMIUM[item.type];
65	
66	const COMPONENT_BLOCK_PREMIUM = 60;
67	
68	const sumBasePremiums = (items: Item[]): number =>
69	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
70	
71	const COMPONENT_TYPES = ["rune", "moonstone"];
72	
73	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
74	
75	const componentGroupTotal = (group: Item[]): number =>
76	  group.length === 3 ? COMPONENT_BLOCK_PREMIUM : sumBasePremiums(group);
77	
78	const componentsTotal = (items: Item[]): number =>
79	  COMPONENT_TYPES.reduce(
80	    (sum, type) => sum + componentGroupTotal(items.filter((i) => i.type === type)),
81	    0,
82	  );
83	
84	const itemsBaseTotal = (items: Item[]): number =>
85	  sumBasePremiums(items.filter((i) => !isComponent(i))) + componentsTotal(items);
86	
87	const CURSE_SURCHARGE_RATE = 0.5;
88	const HIGH_ENCHANTMENT_THRESHOLD = 5;
89	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
90	
91	const isCursed = (item: Item): boolean => item.cursed === true;
92	const isHighlyEnchanted = (item: Item): boolean =>
93	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
94	
95	const ITEM_SURCHARGE_RATES: ReadonlyArray<(item: Item) => number> = [
96	  (item) => (isCursed(item) ? CURSE_SURCHARGE_RATE : 0),
97	  (item) => (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0),
98	];
99	
100	const itemSurchargeRate = (item: Item): number =>
101	  ITEM_SURCHARGE_RATES.reduce((sum, rate) => sum + rate(item), 0);
102	
103	const itemSurcharges = (items: Item[]): number =>
104	  items.reduce((sum, item) => sum + basePremiumFor(item) * itemSurchargeRate(item), 0);
105	
106	const LOYALTY_THRESHOLD_YEARS = 2;
107	const LOYALTY_DISCOUNT_RATE = 0.2;
108	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
109	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
110	
111	const isLoyal = (customer: Customer): boolean =>
112	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
113	
114	const policyDiscountRate = (customer: Customer): number =>
115	  isLoyal(customer) ? LOYALTY_DISCOUNT_RATE : 0;
116	
117	const followUpDiscountRate = (isFollowUp: boolean): number =>
118	  isFollowUp ? FOLLOW_UP_DISCOUNT_RATE : 0;
119	
120	const policyAdjustedBase = (
121	  baseTotal: number,
122	  customer: Customer,
123	  isFollowUp: boolean,
124	): number =>
125	  baseTotal * (1 - policyDiscountRate(customer) - followUpDiscountRate(isFollowUp)) +
126	  baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
127	
128	const quote = (
129	  { items }: QuoteStep,
130	  customer: Customer,
131	  isFollowUp: boolean,
132	): QuoteResult => ({
133	  premium: Math.ceil(
134	    policyAdjustedBase(itemsBaseTotal(items), customer, isFollowUp) +
135	      itemSurcharges(items) +
136	      PROCESSING_FEE,
137	  ),
138	});
139	
140	const hasPriorQuote = (steps: Step[], index: number): boolean =>
141	  steps.slice(0, index).some((s) => s.op === "quote");
142	
143	const ITEM_INSURANCE_VALUE: Record<string, number> = {
144	  sword: 1000,
145	  amulet: 600,
146	  staff: 800,
147	  potion: 400,
148	  rune: 250,
149	  moonstone: 250,
150	};
151	
152	const insuranceValueFor = (item: Item): number => ITEM_INSURANCE_VALUE[item.type];
153	
154	const insuranceSum = (items: Item[]): number =>
155	  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
156	
157	const DEDUCTIBLE = 100;
158	const CAP_MULTIPLIER = 2;
159	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
160	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
161	
162	const reimbursementRate = (item: Item): number =>
163	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
164	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
165	    : 1;
166	
167	const damagePayout = (damage: Damage, item: Item): number =>
168	  damage.amount * reimbursementRate(item) - DEDUCTIBLE;
169	
170	const matchPolicyItem = (items: Item[], damage: Damage): Item =>
171	  items.find((i) => i.type === damage.itemType) as Item;
172	
173	const totalPayout = (damages: Damage[], items: Item[]): number =>
174	  damages.reduce((sum, d) => sum + damagePayout(d, matchPolicyItem(items, d)), 0);
175	
176	const insuranceCap = (items: Item[]): number => insuranceSum(items) * CAP_MULTIPLIER;
177	
178	const policyItems = (steps: Step[], policyIndex: number): Item[] =>
179	  (steps[policyIndex] as QuoteStep).items;
180	
181	const claim = (step: ClaimStep, steps: Step[]): ClaimResult => {
182	  const items = policyItems(steps, step.policy);
183	  const payout = totalPayout(step.incident.damages, items);
184	  const cap = insuranceCap(items);
185	  return { payout, remainingCap: cap - payout };
186	};
187	
188	export const runScenario = (scenario: Scenario): ScenarioResult => ({
189	  results: scenario.steps.map((step, index) =>
190	    step.op === "quote"
191	      ? quote(step, scenario.customer, hasPriorQuote(scenario.steps, index))
192	      : claim(step, scenario.steps),
193	  ),
194	});
